import os
from flask import Flask, request, jsonify, Response
import jwt
from functools import wraps
import requests
from datetime import datetime, timedelta

app = Flask(__name__)

# Secure configuration
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')
if not app.config['SECRET_KEY']:
    raise ValueError("JWT_SECRET_KEY environment variable must be set")

app.config['JWT_ALGORITHM'] = os.environ.get('JWT_ALGORITHM', 'HS256')
app.config['JWT_EXPIRATION_DELTA'] = int(os.environ.get('JWT_EXPIRATION_DELTA', 3600))
app.config['BACKEND_SERVICE_URL'] = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')

# Allowed algorithms for JWT verification
ALLOWED_ALGORITHMS = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']

if app.config['JWT_ALGORITHM'] not in ALLOWED_ALGORITHMS:
    raise ValueError(f"JWT_ALGORITHM must be one of {ALLOWED_ALGORITHMS}")


def validate_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = None
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            return jsonify({'error': 'Authorization header is missing'}), 401
        
        try:
            parts = auth_header.split()
            if len(parts) != 2 or parts[0].lower() != 'bearer':
                return jsonify({'error': 'Invalid authorization header format. Use: Bearer <token>'}), 401
            
            token = parts[1]
        except Exception:
            return jsonify({'error': 'Invalid authorization header'}), 401
        
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        try:
            # SECURE: Always verify JWT tokens with proper signature verification
            # verify=False is NEVER acceptable in production or development
            payload = jwt.decode(
                token,
                app.config['SECRET_KEY'],
                algorithms=[app.config['JWT_ALGORITHM']],
                options={
                    'verify_signature': True,
                    'verify_exp': True,
                    'verify_nbf': True,
                    'verify_iat': True,
                    'require_exp': True
                }
            )
            
            # Validate required claims
            required_claims = ['user_id', 'exp']
            for claim in required_claims:
                if claim not in payload:
                    return jsonify({'error': f'Missing required claim: {claim}'}), 401
            
            # Additional security checks
            current_time = datetime.utcnow().timestamp()
            
            # Check expiration
            if payload.get('exp', 0) < current_time:
                return jsonify({'error': 'Token has expired'}), 401
            
            # Check not before (if present)
            if 'nbf' in payload and payload['nbf'] > current_time:
                return jsonify({'error': 'Token not yet valid'}), 401
            
            # Validate user_id format
            user_id = payload.get('user_id')
            if not isinstance(user_id, (str, int)) or (isinstance(user_id, str) and not user_id.strip()):
                return jsonify({'error': 'Invalid user_id in token'}), 401
            
            request.user_claims = payload
            
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError as e:
            return jsonify({'error': f'Invalid token: {str(e)}'}), 401
        except Exception as e:
            app.logger.error(f'Token validation error: {str(e)}')
            return jsonify({'error': 'Token validation failed'}), 401
        
        return f(*args, **kwargs)
    
    return decorated_function


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200


@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
@validate_token
def gateway(path):
    try:
        user_claims = request.user_claims
        
        # Sanitize and prepare headers for backend
        backend_headers = {
            'X-User-Id': str(user_claims.get('user_id', '')),
            'X-User-Email': str(user_claims.get('email', '')),
            'X-User-Roles': ','.join(user_claims.get('roles', [])) if isinstance(user_claims.get('roles'), list) else '',
            'Content-Type': request.headers.get('Content-Type', 'application/json')
        }
        
        # Remove sensitive headers
        safe_headers = {}
        for key, value in request.headers.items():
            if key.lower() not in ['authorization', 'cookie', 'x-api-key']:
                safe_headers[key] = value
        
        backend_headers.update(safe_headers)
        
        # Construct backend URL
        backend_url = f"{app.config['BACKEND_SERVICE_URL']}/{path}"
        
        # Validate backend URL
        if not backend_url.startswith(('http://', 'https://')):
            return jsonify({'error': 'Invalid backend URL'}), 500
        
        # Forward request to backend service
        try:
            response = requests.request(
                method=request.method,
                url=backend_url,
                headers=backend_headers,
                params=request.args,
                json=request.get_json(silent=True) if request.is_json else None,
                data=request.get_data() if not request.is_json else None,
                timeout=30,
                allow_redirects=False
            )
            
            # Create response with backend data
            excluded_headers = ['content-encoding', 'content-length', 'transfer-encoding', 'connection']
            headers = [(name, value) for (name, value) in response.headers.items()
                      if name.lower() not in excluded_headers]
            
            return Response(response.content, response.status_code, headers)
            
        except requests.exceptions.Timeout:
            return jsonify({'error': 'Backend service timeout'}), 504
        except requests.exceptions.ConnectionError:
            return jsonify({'error': 'Backend service unavailable'}), 503
        except requests.exceptions.RequestException as e:
            app.logger.error(f'Backend request error: {str(e)}')
            return jsonify({'error': 'Backend service error'}), 502
            
    except Exception as e:
        app.logger.error(f'Gateway error: {str(e)}')
        return jsonify({'error': 'Internal gateway error'}), 500


@app.route('/auth/token', methods=['POST'])
def generate_token():
    """Generate JWT token for testing purposes - should be replaced with proper auth service"""
    try:
        data = request.get_json()
        
        if not data or 'user_id' not in data:
            return jsonify({'error': 'user_id is required'}), 400
        
        user_id = data.get('user_id')
        email = data.get('email', '')
        roles = data.get('roles', [])
        
        # Validate input
        if not isinstance(user_id, (str, int)) or (isinstance(user_id, str) and not user_id.strip()):
            return jsonify({'error': 'Invalid user_id'}), 400
        
        if not isinstance(roles, list):
            return jsonify({'error': 'roles must be a list'}), 400
        
        expiration = datetime.utcnow() + timedelta(seconds=app.config['JWT_EXPIRATION_DELTA'])
        
        payload = {
            'user_id': user_id,
            'email': email,
            'roles': roles,
            'exp': expiration,
            'iat': datetime.utcnow(),
            'nbf': datetime.utcnow()
        }
        
        token = jwt.encode(
            payload,
            app.config['SECRET_KEY'],
            algorithm=app.config['JWT_ALGORITHM']
        )
        
        return jsonify({
            'token': token,
            'expires_at': expiration.isoformat()
        }), 200
        
    except Exception as e:
        app.logger.error(f'Token generation error: {str(e)}')
        return jsonify({'error': 'Token generation failed'}), 500


